diff --git a/llvm/lib/Transforms/Utils/Local.cpp b/llvm/lib/Transforms/Utils/Local.cpp
index 65c1669f92b4..c0d98bddcb33 100644
--- a/llvm/lib/Transforms/Utils/Local.cpp
+++ b/llvm/lib/Transforms/Utils/Local.cpp
@@ -3518,6 +3518,64 @@ void llvm::patchReplacementInstruction(Instruction *I, Value *Repl) {
   // regions, and so we need a conservative combination of the noalias
   // scopes.
   combineMetadataForCSE(ReplInst, I, false);
+
+  // If the replacement has result !range metadata that is different from the
+  // original, conservatively drop it to avoid making the replacement more
+  // poisonous at new use sites. Result !range can turn otherwise well-defined
+  // values into poison when the actual runtime value falls outside the stated
+  // range; propagating a stricter range into uses that were not proven to
+  // satisfy it is not correct.
+  // Only adjust result !range when replacing across different basic blocks.
+  // Using a value with stricter !range in a different block can introduce
+  // poison on paths where the stricter range does not hold. If both instructions
+  // are in the same block, we keep the replacement's metadata untouched.
+  if (ReplInst->getParent() != I->getParent()) {
+    // Adjust result !range metadata only for non-load instructions to avoid
+    // interfering with load range combination logic in NewGVN/GVN.
+    if (!isa<LoadInst>(ReplInst)) {
+      if (MDNode *ReplRange = ReplInst->getMetadata(LLVMContext::MD_range)) {
+        MDNode *OrigRange = I->getMetadata(LLVMContext::MD_range);
+        if (OrigRange && OrigRange != ReplRange)
+          // Prefer the original (usually wider) range to avoid making the
+          // replacement more poisonous at new use sites.
+          ReplInst->setMetadata(LLVMContext::MD_range, OrigRange);
+        else if (!OrigRange)
+          // If the original did not have a range, drop the replacement's range
+          // to avoid strengthening semantics across blocks.
+          ReplInst->setMetadata(LLVMContext::MD_range, nullptr);
+      }
+    }
+
+    // Also adjust return value range attribute on calls. The 'range' return
+    // attribute can introduce poison if it is stricter than the original being
+    // replaced. If the replacement call has a return range attribute that
+    // differs from the original (or the original lacks one), align it to the
+    // original or drop it conservatively.
+    if (auto *ReplCB = dyn_cast<CallBase>(ReplInst)) {
+      AttributeList ReplAL = ReplCB->getAttributes();
+      if (ReplAL.hasRetAttr(Attribute::Range)) {
+        AttributeList NewAL = ReplAL;
+        if (auto *OrigCB = dyn_cast<CallBase>(I)) {
+          AttributeList OrigAL = OrigCB->getAttributes();
+          if (OrigAL.hasRetAttr(Attribute::Range)) {
+            Attribute ReplRA = ReplAL.getRetAttr(Attribute::Range);
+            Attribute OrigRA = OrigAL.getRetAttr(Attribute::Range);
+            if (ReplRA != OrigRA)
+              NewAL = NewAL.removeRetAttribute(ReplCB->getContext(), Attribute::Range)
+                           .addRetAttribute(ReplCB->getContext(), OrigRA);
+          } else {
+            // Original lacked a return range; drop the replacement's.
+            NewAL = NewAL.removeRetAttribute(ReplCB->getContext(), Attribute::Range);
+          }
+        } else {
+          // Original wasn't a call; drop the replacement's return range.
+          NewAL = NewAL.removeRetAttribute(ReplCB->getContext(), Attribute::Range);
+        }
+        ReplCB->setAttributes(NewAL);
+      }
+    }
+  }
+
 }

